import { Pool } from 'pg';
import { ILeavePolicyRepository } from '../policy.repository';
import { LeavePolicy, CreateLeavePolicyDto, UpdateLeavePolicyDto, LeavePolicyType } from '../policy.model';

export class PostgresLeavePolicyRepository implements ILeavePolicyRepository {
  constructor(private readonly pool: Pool) {}

  async create(dto: CreateLeavePolicyDto): Promise<LeavePolicy> {
    const client = await this.pool.connect();
    try {
      const query = `
        INSERT INTO leave_policies (
          policy_name, leave_type, entitlement_days, accrual_rate,
          max_carryover, requires_approval, is_active
        ) VALUES ($1, $2, $3, $4, $5, $6, $7)
        RETURNING *
      `;
      const values = [
        dto.policyName,
        dto.leaveType,
        dto.entitlementDays,
        dto.accrualRate ?? null,
        dto.maxCarryover ?? null,
        dto.requiresApproval ?? true,
        dto.isActive ?? true
      ];

      const result = await client.query(query, values);
      return this.mapRowToLeavePolicy(result.rows[0]);
    } finally {
      client.release();
    }
  }

  async findById(id: string): Promise<LeavePolicy | null> {
    const result = await this.pool.query(
      'SELECT * FROM leave_policies WHERE id = $1',
      [id]
    );
    return result.rows.length > 0 ? this.mapRowToLeavePolicy(result.rows[0]) : null;
  }

  async findAll(): Promise<LeavePolicy[]> {
    const result = await this.pool.query('SELECT * FROM leave_policies ORDER BY policy_name');
    return result.rows.map(row => this.mapRowToLeavePolicy(row));
  }

  async findByLeaveType(leaveType: string): Promise<LeavePolicy[]> {
    const result = await this.pool.query(
      'SELECT * FROM leave_policies WHERE leave_type = $1 ORDER BY policy_name',
      [leaveType]
    );
    return result.rows.map(row => this.mapRowToLeavePolicy(row));
  }

  async findActivePolicies(): Promise<LeavePolicy[]> {
    const result = await this.pool.query(
      'SELECT * FROM leave_policies WHERE is_active = true ORDER BY policy_name'
    );
    return result.rows.map(row => this.mapRowToLeavePolicy(row));
  }

  async update(id: string, dto: UpdateLeavePolicyDto): Promise<LeavePolicy> {
    const client = await this.pool.connect();
    try {
      const updates: string[] = [];
      const values: any[] = [];
      let paramCount = 1;

      if (dto.policyName !== undefined) {
        updates.push(`policy_name = $${paramCount}`);
        values.push(dto.policyName);
        paramCount++;
      }
      if (dto.leaveType !== undefined) {
        updates.push(`leave_type = $${paramCount}`);
        values.push(dto.leaveType);
        paramCount++;
      }
      if (dto.entitlementDays !== undefined) {
        updates.push(`entitlement_days = $${paramCount}`);
        values.push(dto.entitlementDays);
        paramCount++;
      }
      if (dto.accrualRate !== undefined) {
        updates.push(`accrual_rate = $${paramCount}`);
        values.push(dto.accrualRate);
        paramCount++;
      }
      if (dto.maxCarryover !== undefined) {
        updates.push(`max_carryover = $${paramCount}`);
        values.push(dto.maxCarryover);
        paramCount++;
      }
      if (dto.requiresApproval !== undefined) {
        updates.push(`requires_approval = $${paramCount}`);
        values.push(dto.requiresApproval);
        paramCount++;
      }
      if (dto.isActive !== undefined) {
        updates.push(`is_active = $${paramCount}`);
        values.push(dto.isActive);
        paramCount++;
      }

      if (updates.length === 0) {
        const existing = await this.findById(id);
        if (!existing) throw new Error(`Leave policy with id ${id} not found`);
        return existing;
      }

      updates.push(`updated_at = CURRENT_TIMESTAMP`);
      values.push(id);

      const query = `
        UPDATE leave_policies
        SET ${updates.join(', ')}
        WHERE id = $${paramCount}
        RETURNING *
      `;

      const result = await client.query(query, values);
      if (result.rows.length === 0) {
        throw new Error(`Leave policy with id ${id} not found`);
      }
      return this.mapRowToLeavePolicy(result.rows[0]);
    } finally {
      client.release();
    }
  }

  async deactivate(id: string): Promise<LeavePolicy> {
    const client = await this.pool.connect();
    try {
      const query = `
        UPDATE leave_policies
        SET is_active = false, updated_at = CURRENT_TIMESTAMP
        WHERE id = $1
        RETURNING *
      `;
      const result = await client.query(query, [id]);
      if (result.rows.length === 0) {
        throw new Error(`Leave policy with id ${id} not found`);
      }
      return this.mapRowToLeavePolicy(result.rows[0]);
    } finally {
      client.release();
    }
  }

  private mapRowToLeavePolicy(row: any): LeavePolicy {
    return {
      id: row.id,
      policyName: row.policy_name,
      leaveType: row.leave_type as LeavePolicyType,
      entitlementDays: row.entitlement_days,
      accrualRate: row.accrual_rate,
      maxCarryover: row.max_carryover,
      requiresApproval: row.requires_approval,
      isActive: row.is_active,
      createdAt: row.created_at,
      updatedAt: row.updated_at
    };
  }
